external_knowledge:
- 'Explorers' refers to users; 
- 'Vast gallery of data' is a metaphor for the collection of observations; 
- 'Paintings' symbolize individual observations; 
- 'Gaze upon' is a metaphor for the act of viewing an observation.

sql:
SELECT station_name
FROM stations
WHERE elevation > (SELECT AVG(elevation) FROM stations);

SELECT type_id, obs_id 
FROM observation_types 
WHERE type_id > 5;

SELECT DISTINCT s.station_name, s.location
FROM stations s
INNER JOIN observations o ON s.station_id = o.station_id;

SELECT COUNT(*) 
FROM observations 
WHERE station_id = 1;

